<style lang="scss">
  @use '/src/styles/abstracts' as *;

  .icon-loading-portal {
    // Override .icon base square sizing — this is a rectangular scene
    width: 100%;
    height: auto;
    aspect-ratio: 1376 / 768; // void-ignore

    --spin-duration: 20s;
    --pulse-duration: 4s;
    --ease-pulse: cubic-bezier(0.33, 1, 0.68, 1);

    .outer-circuitry {
      fill: tint(var(--energy-primary), 50%);
    }

    .inner-circuitry {
      fill: tint(var(--energy-primary), 50%);
      transform-box: fill-box;
      transform-origin: center;
    }

    // ── Idle state ──
    &[data-status='idle'] {
      .outer-circuitry {
        opacity: 0.5;
      }

      .inner-circuitry {
        opacity: 0.5;
      }
    }

    // ── Loading state ──
    &[data-status='loading'] {
      .outer-circuitry {
        will-change: opacity;
        animation: circuit-pulse var(--pulse-duration) var(--ease-pulse)
          infinite;
      }

      .inner-circuitry {
        will-change: transform;
        animation: portal-spin var(--spin-duration) linear infinite;
      }
    }
  }

  // ── Glass physics: bloom ──
  :global([data-physics='glass'] .icon-loading-portal[data-status='loading']) {
    .outer-circuitry {
      filter: drop-shadow(0 0 6px var(--energy-primary)) // void-ignore
        drop-shadow(0 0 18px var(--energy-primary)); // void-ignore
    }

    .inner-circuitry {
      filter: drop-shadow(0 0 6px var(--energy-primary)) // void-ignore
        drop-shadow(0 0 18px var(--energy-primary)); // void-ignore
    }
  }

  // ── Retro physics: fast stepped timing ──
  :global([data-physics='retro'] .icon-loading-portal[data-status='loading']) {
    .outer-circuitry {
      animation-timing-function: steps(4);
      animation-duration: 2s;
    }

    .inner-circuitry {
      animation-timing-function: steps(12);
      animation-duration: 8s;
    }
  }

  // ── Light mode: dark crisp circuits, no glow ──
  :global([data-mode='light'] .icon-loading-portal) {
    .outer-circuitry,
    .inner-circuitry {
      fill: var(--energy-primary);
      filter: none !important;
    }
  }

  // ── Retro: clean lines, no glow ──
  :global([data-physics='retro'] .icon-loading-portal) {
    .outer-circuitry,
    .inner-circuitry {
      fill: var(--energy-primary);
      filter: none !important;
    }
  }

  // ── Reduced motion: static fallback ──
  @media (prefers-reduced-motion: reduce) {
    .icon-loading-portal[data-status='loading'] {
      .outer-circuitry {
        opacity: 0.4;
      }

      .inner-circuitry {
        opacity: 0.6;
      }
    }
  }

  @keyframes circuit-pulse {
    0%,
    100% {
      opacity: 0.5;
    }
    50% {
      opacity: 1;
    }
  }

  @keyframes portal-spin {
    from {
      rotate: 0deg;
    }
    to {
      rotate: 360deg;
    }
  }
</style>
